{"command":"python3 - <<'PY'
import json
from pathlib import Path

project = Path('/home/bitzaven/CodingProjects/pi-threads/.pi/threads')
artifacts = Path('/tmp/pi-threads-bugsearch')

def parse_session(path: Path):
    entries = []
    for line in path.read_text().splitlines():
        obj = json.loads(line)
        if obj.get('type') != 'message':
            continue
        msg = obj.get('message', {})
        entries.append({
            'role': msg.get('role'),
            'timestamp': msg.get('timestamp') or obj.get('timestamp'),
            'toolName': msg.get('toolName'),
            'texts': [part.get('text') for part in msg.get('content', []) if isinstance(part, dict) and 'text' in part],
        })
    return entries

summary = {}
for name in ['bugsleep-par-1','bugsleep-par-2','bugsleep-par-3','bugqueue']:
    session = project / f'{name}.jsonl'
    entries = parse_session(session)
    summary[name] = {
        'messageCount': len(entries),
        'roles': [e['role'] for e in entries],
        'timestamps': [e['timestamp'] for e in entries],
        'texts': [t for e in entries for t in e['texts'] if t],
    }
(artifacts / 'session-timing-summary.json').write_text(json.dumps(summary, indent=2) + '\n')
PY
